"@import "tailwindcss";

@theme {
  --font-sans: "Plus Jakarta Sans", ui-sans-serif, system-ui, sans-serif;
  --color-primary: #8b5cf6;
  --color-primary-container: #a78bfa;
  --color-on-primary: #ffffff;
  --color-secondary-fixed: #1e1b4b;
  --color-secondary-fixed-dim: #312e81;
  --color-surface-container: #131926;
  --color-surface-container-low: #0f131f;
  --color-on-surface: #ffffff;
  --color-on-surface-variant: #94a3b8;
  --color-outline: rgba(255,255,255,0.08);
  --color-outline-variant: rgba(255,255,255,0.15);
  --color-error-container: #7f1d1d;
  --color-on-error-container: #fca5a5;
  --color-success: #10b981;
  --color-soft-lavender: #090D16;
}

*, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; }
html { scroll-behavior: smooth; -webkit-text-size-adjust: 100%; }

body {
  font-family: var(--font-sans);
  background-color: var(--color-soft-lavender);
  color: #ffffff;
  min-height: 100dvh;
  -webkit-font-smoothing: antialiased;
  overflow-x: hidden;
}

/* ── App shell layout ─────────────────────────────────────────── */
.app-shell {
  display: flex;
  min-height: 100vh;
}

/* Sidebar: hidden on mobile/tablet, sticky column on desktop */
.app-sidebar {
  display: none;
  flex-direction: column;
  width: 256px;
  flex-shrink: 0;
  position: sticky;
  top: 0;
  height: 100vh;
  overflow-y: auto;
}
@media (min-width: 1024px) { .app-sidebar { display: flex; } }

/* Content fills remaining space */
.app-content {
  flex: 1;
  min-width: 0;
  display: flex;
  flex-direction: column;
}

/* ── Glass utilities ────────────────────────────────────────────── */
.glass-panel {
  background: rgba(15, 23, 42, 0.45);
  backdrop-filter: blur(16px);
  -webkit-backdrop-filter: blur(16px);
  border: 1px solid rgba(255,255,255,0.08);
}
